SELECT id, alert_type AS alertType, severity, title, message, source,
       status, resolved_by AS resolvedBy, resolved_at AS resolvedAt,
       resolve_remark AS resolveRemark, created_at AS createdAt
FROM system_alerts


        AND alert_type = #{alertType}


        AND severity = #{severity}


        AND status = #{status}


ORDER BY created_at DESC
LIMIT #{offset}, #{limit}

